package device

import (
	"context"
	"net/netip"
	"sync"
	"time"

	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/dnsresolve"
	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/telemetry"
)

// nameTarget is one hostname endpoint spec the re-resolution controller tracks: the index of
// its owning failoverSpec (which equals the entry's position in config.Peer.EndpointSpecs, since
// the failover specs are built 1:1 in TOML order) together with the host/port to resolve. Only
// hostname specs (EndpointSpec.IsName) become nameTargets; literal specs never re-resolve.
type nameTarget struct {
	specIdx int
	host    string
	port    uint16
}

// resolution is the edge-side re-resolution controller (Q31/T73). It re-resolves each opted-in
// hostname peer-endpoint spec on a fixed poll cadence AND out-of-band the instant every path to
// the ACTIVE concentrator goes DOWN, then hands the fresh record set to hubFailover's update API
// so the bond is repointed only on an ACTUAL change (D32 suppression lives inside updateResolution).
//
// It mirrors the hubFailover shape: a pure constructor over injected collaborators (a
// dnsresolve.Resolver, the hubFailover whose update API / active-spec identity / shared liveness
// plane it drives, a telemetry.Clock, and the [dns] poll interval + per-lookup timeout), so its
// decision logic is unit-testable against a fake resolver, a fake clock, and a hubFailover built
// over fake health/remote. Resolution runs entirely OFF the send hot path — its own goroutine
// performs the network lookups; results are applied only through updateResolution under the
// endpoint-set lock (Q34: the two controllers coordinate purely through that shared lock and the
// update API, never a second, competing repoint path).
//
// RETENTION INVARIANT (D46): a lookup that FAILS (error/timeout/NXDOMAIN) or yields an EMPTY
// address set NEVER publishes — the spec keeps its last-good expansion and the controller retries
// next tick. A working endpoint set is therefore never torn down by a transient resolver fault,
// and hubFailover never sees an empty active spec that its total<2 guard could strand the bond on.
type resolution struct {
	resolver dnsresolve.Resolver
	// fo is the hub-failover controller this resolver drives: the sole mutation point
	// (updateResolution), the active-spec identity, and the shared liveness plane all live there.
	fo *hubFailover
	// targets is the ordered set of hostname specs to re-resolve; empty for an all-literal peer,
	// in which case the loop is a no-op.
	targets []nameTarget
	// families is the set of IP families the local path sockets can source traffic from (a v4
	// source_addr path reaches only v4 endpoints, a v6 path only v6). A resolved address of a
	// family NO local path can source is unreachable and is dropped from a spec's expansion — else
	// an AAAA-only answer on v4-only paths would repoint the bond at an address no path can carry.
	families pathFamilies

	clock        telemetry.Clock
	pollInterval time.Duration
	timeout      time.Duration
	log          log.Logger

	mu sync.Mutex
	// nextPollAt is when the next SCHEDULED full poll of every hostname spec is due (clock time).
	// Initialized to construction time so the first step polls immediately (prompt boot adoption
	// for a hostname-only peer). Advanced by the TTL-clamped poll delay after each poll, and reset
	// after an out-of-band liveness-loss re-resolve so the two do not double-resolve back to back.
	// Guarded by mu.
	nextPollAt time.Time
	// lastAllDown is the previous liveness-loss reading, so the out-of-band re-resolve is
	// EDGE-triggered (fires once when hub loss is first observed, not every tick while it
	// persists — the poll loop covers a sustained outage without hammering the resolver).
	// Guarded by mu.
	lastAllDown bool
}

// newResolution builds the controller over its injected collaborators. It is a pure constructor
// (no goroutine, no engine dependency) so a test drives step/pollAll directly against a fake
// resolver and a fake clock. nextPollAt is armed at construction time so the first step polls
// immediately.
func newResolution(resolver dnsresolve.Resolver, fo *hubFailover, targets []nameTarget, families pathFamilies, clock telemetry.Clock, pollInterval, timeout time.Duration, lg log.Logger) *resolution {
	return &resolution{
		resolver:     resolver,
		fo:           fo,
		targets:      targets,
		families:     families,
		clock:        clock,
		pollInterval: pollInterval,
		timeout:      timeout,
		log:          lg,
		nextPollAt:   clock.Now(),
	}
}

// nameTargetsFromSpecs extracts the hostname specs (EndpointSpec.IsName) from an ordered spec
// list as nameTargets, tagging each with its index in that list — which equals its failoverSpec
// index, since both are built 1:1 in TOML order. Literal specs contribute nothing.
func nameTargetsFromSpecs(specs []config.EndpointSpec) []nameTarget {
	var ts []nameTarget
	for i, s := range specs {
		if s.IsName {
			ts = append(ts, nameTarget{specIdx: i, host: s.Host, port: s.Port})
		}
	}
	return ts
}

// pathFamilies records which IP families the local path sockets can source traffic from. A path
// binds a socket whose family is fixed by its source_addr (bind.listenOnDevice): a v4 source can
// only reach v4 endpoints, a v6 source only v6. Re-resolution filters a resolved record set to the
// families at least one local path can source, so a lookup answer of an unreachable family (an
// AAAA-only answer on a v4-only edge) never repoints the bond at an address no path can carry.
type pathFamilies struct {
	v4 bool
	v6 bool
}

// allows reports whether a resolved address's family can be sourced by at least one local path.
func (f pathFamilies) allows(a netip.Addr) bool {
	if a.Unmap().Is4() {
		return f.v4
	}
	return f.v6
}

// pathFamiliesFromPaths derives the usable-family set from the configured paths. Config validation
// guarantees every path carries a valid source_addr (Config.normalize), so each path contributes
// exactly one family and the result is non-empty for any peer that reaches this controller.
func pathFamiliesFromPaths(paths []config.Path) pathFamilies {
	var f pathFamilies
	for _, p := range paths {
		if p.SourceAddr.Unmap().Is4() {
			f.v4 = true
		} else {
			f.v6 = true
		}
	}
	return f
}

// step is one evaluation at the probe cadence: it first services a liveness-loss edge (an
// out-of-band re-resolve of the active spec the instant every path goes DOWN), then, if the
// scheduled poll is due, re-resolves every hostname spec and re-arms the next poll at the
// TTL-clamped cadence. It is cheap in the steady state (a liveness read plus a clock compare)
// and performs its network lookups off any lock, so a periodic loop may call it at probe cadence.
func (r *resolution) step() {
	r.checkLivenessLoss()

	r.mu.Lock()
	due := !r.clock.Now().Before(r.nextPollAt)
	r.mu.Unlock()
	if !due {
		return
	}
	delay := r.pollAll()
	r.mu.Lock()
	r.nextPollAt = r.clock.Now().Add(delay)
	r.mu.Unlock()
}

// pollAll re-resolves every tracked hostname spec once and returns the delay until the next
// scheduled poll: the configured poll interval, CLAMPED to the smallest positive TTL reported by
// any spec whose transport exposes one (DoH/DoT ttlOk) — the Q31 TTL nice-to-have — so a record
// about to expire is re-checked no later than its TTL. A lookup failure or empty result leaves
// that spec's expansion untouched (RETENTION INVARIANT) and does not shorten the delay.
func (r *resolution) pollAll() time.Duration {
	delay := r.pollInterval
	for _, t := range r.targets {
		if d := r.clampPollDelay(r.resolveTarget(t)); d < delay {
			delay = d
		}
	}
	return delay
}

// clampPollDelay returns the scheduled poll interval clamped DOWN to a positive, meaningful TTL,
// so a record about to expire is re-checked no later than its TTL (Q31 TTL clamp). A lookup that
// exposes no TTL (ttlOk=false — system resolver) or a non-positive one leaves the full interval.
// It is applied uniformly to the scheduled poll re-arm AND the out-of-band liveness-loss re-arm,
// so the clamp invariant holds on BOTH paths — including the hub-loss window where record
// freshness matters most.
func (r *resolution) clampPollDelay(minTTL time.Duration, ttlOk bool) time.Duration {
	if ttlOk && minTTL > 0 && minTTL < r.pollInterval {
		return minTTL
	}
	return r.pollInterval
}

// resolveTarget performs one context-bounded lookup for a single hostname spec and, on a
// non-empty SUCCESS, hands the family-filtered, ordered record set to hubFailover.updateResolution (which
// suppresses a no-op change and repoints only on an actual active-IP change). It returns the
// lookup's minimum TTL and whether that TTL is meaningful, for the caller's clamp.
//
// RETENTION INVARIANT (D46): on ANY failure (error/timeout/NXDOMAIN) OR an empty ordered set
// (NODATA / a CNAME-only chain / a family the local paths cannot use), it publishes NOTHING —
// the spec keeps its previous expansion — and reports (0, false). A previously-resolved hostname
// is therefore never collapsed to empty, which is exactly the condition that could strand the
// bond under hubFailover's total<2 guard.
func (r *resolution) resolveTarget(t nameTarget) (time.Duration, bool) {
	ctx, cancel := r.lookupContext()
	defer cancel()

	addrs, minTTL, ttlOk, err := r.resolver.Lookup(ctx, t.host)
	if err != nil {
		r.log.Debug("dns re-resolution: lookup failed; retaining last-good records",
			"host", t.host, "spec_index", t.specIdx, "error", err.Error())
		return 0, false
	}
	eps := orderAddrPorts(addrs, t.port, r.families)
	if len(eps) == 0 {
		r.log.Debug("dns re-resolution: no usable record for local path families; retaining last-good records",
			"host", t.host, "spec_index", t.specIdx)
		return 0, false
	}
	r.fo.updateResolution(t.specIdx, eps)
	return minTTL, ttlOk
}

// checkLivenessLoss fires the out-of-band re-resolve of the ACTIVE spec on the DOWN edge — the
// tick at which every path to the active concentrator first reads DOWN. It coordinates with
// hubFailover purely through the shared liveness read (allPathsDown) and active-spec identity
// (activeSpecIndex): a hub-loss advance and a liveness-loss re-resolve therefore derive from one
// detector. The trigger is edge-triggered so a sustained outage re-resolves once here (the poll
// loop covers the rest) rather than on every tick.
func (r *resolution) checkLivenessLoss() {
	down := r.fo.allPathsDown()

	r.mu.Lock()
	edge := down && !r.lastAllDown
	r.lastAllDown = down
	r.mu.Unlock()
	if !edge {
		return
	}

	active := r.fo.activeSpecIndex()
	t, ok := r.targetFor(active)
	if !ok {
		// The active spec is a literal (or there is no active entry yet): nothing to re-resolve.
		return
	}
	r.log.Warn("dns re-resolution: all paths to active concentrator down; out-of-band re-resolve",
		"host", t.host, "spec_index", t.specIdx)
	minTTL, ttlOk := r.resolveTarget(t)

	// An out-of-band re-resolve subsumes the scheduled poll for this instant; push the next poll
	// out — but re-arm at the TTL-CLAMPED delay, not a blind full interval, so a short-TTL record
	// is re-checked no later than its TTL on exactly the hub-loss path where freshness matters most.
	r.mu.Lock()
	r.nextPollAt = r.clock.Now().Add(r.clampPollDelay(minTTL, ttlOk))
	r.mu.Unlock()
}

// targetFor returns the nameTarget owning specIdx, or ok=false when no tracked hostname spec has
// that index (a literal active spec, or specIdx == -1 for no active entry).
func (r *resolution) targetFor(specIdx int) (nameTarget, bool) {
	if specIdx < 0 {
		return nameTarget{}, false
	}
	for _, t := range r.targets {
		if t.specIdx == specIdx {
			return t, true
		}
	}
	return nameTarget{}, false
}

// lookupContext returns a context bounded by the configured per-lookup timeout (a non-positive
// timeout yields an unbounded context — the caller's config validation keeps it positive).
func (r *resolution) lookupContext() (context.Context, context.CancelFunc) {
	if r.timeout <= 0 {
		return context.WithCancel(context.Background())
	}
	return context.WithTimeout(context.Background(), r.timeout)
}

// orderAddrPorts turns a resolver's mixed A/AAAA record set into the ordered, deduplicated
// []netip.AddrPort a failoverSpec expansion requires: IPv4 records first (in resolver order),
// then IPv6, each paired with the spec's port. The order is DETERMINISTIC so an unchanged DNS
// answer produces a byte-identical expansion tick after tick — the precondition for
// updateResolution's active-AddrPort survival check to suppress a no-op repoint. Invalid or
// duplicate addrs, and addrs of a family NO local path can source (fams), are dropped — so a
// record set that filters down to nothing yields an empty expansion the caller retains last-good on.
func orderAddrPorts(addrs []netip.Addr, port uint16, fams pathFamilies) []netip.AddrPort {
	seen := make(map[netip.Addr]struct{}, len(addrs))
	var v4, v6 []netip.AddrPort
	for _, a := range addrs {
		if !a.IsValid() || !fams.allows(a) {
			continue
		}
		canon := a.Unmap()
		if _, dup := seen[canon]; dup {
			continue
		}
		seen[canon] = struct{}{}
		ap := netip.AddrPortFrom(canon, port)
		if canon.Is4() {
			v4 = append(v4, ap)
		} else {
			v6 = append(v6, ap)
		}
	}
	return append(v4, v6...)
}

// startResolutionLoop launches the re-resolution goroutine: it calls step every interval until
// the returned stopper is invoked (idempotent). It mirrors startHubFailoverLoop — a wall-clock
// ticker at the probe cadence driving a decision method whose every timing choice runs through
// the injected Clock, so a test drives step directly against a fake clock and never starts this
// goroutine. It is a no-op (no-op stopper) for a controller with no hostname specs to track or a
// non-positive interval.
func (r *resolution) startResolutionLoop(interval time.Duration) (stop func()) {
	if len(r.targets) == 0 || interval <= 0 {
		return func() {}
	}
	done := make(chan struct{})
	go func() {
		ticker := time.NewTicker(interval)
		defer ticker.Stop()
		for {
			select {
			case <-done:
				return
			case <-ticker.C:
				r.step()
			}
		}
	}()
	var once sync.Once
	return func() { once.Do(func() { close(done) }) }
}

// Package device brings a wanbond tunnel up from a validated configuration: it
// creates the TUN interface, drives the embedded amneziawg-go engine over the
// multipath Bind, and applies the WireGuard (and, when configured, amnezia
// obfuscation) parameters via the engine's UAPI. It owns ONLY the tunnel engine
// — interface addressing and routing are left to the operator (systemd/wg-quick
// style), so the daemon stays free of privileged shell-outs. The interface name
// is exposed via Tunnel.Name for that external configuration step.
package device

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"reflect"
	"strings"
	"sync"
	"time"

	awgdevice "github.com/amnezia-vpn/amneziawg-go/device"
	"github.com/amnezia-vpn/amneziawg-go/tun"

	"github.com/7mind/wanbond/internal/adaptivefec"
	"github.com/7mind/wanbond/internal/bind"
	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/metrics"
	"github.com/7mind/wanbond/internal/sched"
	"github.com/7mind/wanbond/internal/telemetry"
)

// metricsShutdownTimeout bounds the graceful shutdown of the /metrics endpoint on
// Close (and on a reload that rebinds it). The endpoint is loopback-only with no
// long-lived scrapes, so this is comfortably generous.
const metricsShutdownTimeout = 2 * time.Second

// defaultTUNName is the requested interface name; the kernel honours it unless it
// collides (it never does across the edge and concentrator network namespaces).
const defaultTUNName = "wanbond0"

// tunMTU is the tunnel (TUN) MTU for a config: the default path MTU minus the
// IP+UDP, outer DATA-frame, and WireGuard transport overheads, so a full-MTU inner
// packet never fragments on the wire (see internal/bind mtu.go and docs/p1-mtu.md).
// This is smaller than the plain-WireGuard 1420 because the bonding layer adds its
// own outer DATA frame per datagram; with FEC enabled it is a further
// bind.FECParityMTUPenalty smaller so a full-size PARITY frame also fits the path MTU
// (T24) rather than fragmenting.
func tunMTU(cfg *config.Config) int {
	return bind.InnerMTU(bind.DefaultPathMTU, cfg.FEC.Enabled)
}

// Tunnel is a running wanbond tunnel: the amneziawg engine, its TUN, and the
// multipath Bind. Close tears all three down.
type Tunnel struct {
	dev  *awgdevice.Device
	tun  tun.Device
	name string
	// bind is the multipath Bind the engine drives; Reload calls its runtime
	// AddPath/RemovePath to apply a config-reload path diff (T30).
	bind *bind.Multipath
	// cfg is the configuration the RUNNING tunnel reflects: the boot config, its path
	// set updated on each successful Reload to the current membership (survivors keep
	// their original parameters — a membership-only reload does not re-apply modified
	// path parameters or non-path fields). Reload diffs the next desired config against
	// it to warn about changes it cannot apply. Guarded by reloadMu.
	cfg *config.Config
	// reloadMu serializes Reload against itself (SIGHUP handlers), guarding cfg.
	reloadMu sync.Mutex
	// log is the device-component logger, retained for Reload diagnostics.
	log log.Logger
	// stopProbes halts the per-path probe cadence loop (T37). Close calls it before
	// tearing the engine down so emission stops before the sockets close. It is
	// idempotent and never nil (a no-op when the bind runs without probers).
	stopProbes func()
	// stopReconcile halts the background deferred-path reconcile loop (T55): it retries
	// binding the paths a tolerant Open left DOWN as their addresses appear. Close calls
	// it before tearing the engine down so no reconcile races the socket close. It is
	// idempotent and never nil (a no-op when the bind runs without probers / never defers).
	stopReconcile func()
	// stopHubFailover halts the edge-side hub-failover monitor loop (T57): it watches the
	// per-path liveness plane and, on hub loss (all paths to the active concentrator DOWN),
	// advances to the next ordered peer endpoint, repoints the bond's remote, and initiates
	// a fresh WG re-handshake. Close calls it before tearing the engine down. It is
	// idempotent and never nil (a no-op on the concentrator, or an edge with a single
	// concentrator endpoint, or a bind without the probe transport).
	stopHubFailover func()
	// amnezia is the obfuscation profile this tunnel holds against the
	// process-global amnezia guard (see amneziaGuard); Close releases it.
	amnezia     config.Amnezia
	releaseOnce sync.Once

	// metricsSrc is the live metrics.Source over the Bind; it is stable for the tunnel's
	// life (the Bind pointer never changes), so a reload that rebinds the endpoint reuses
	// the SAME Source — its derived-throughput last-sample state survives the rebind.
	metricsSrc metrics.Source
	// metricsSrv is the running /metrics endpoint, nil when [metrics].listen is empty.
	// It is (re)assigned by applyMetricsLocked and read by Close; both hold reloadMu, so
	// a SIGHUP-driven rebind never races shutdown. metricsListen mirrors the address it
	// is bound to so a reload can detect a listen change without inspecting the server.
	metricsSrv    *metrics.Server
	metricsListen string
}

// SINGLE-ENGINE-PER-PROCESS INVARIANT (defect D2).
//
// amneziawg-go stores the amnezia magic-header message types in PACKAGE-GLOBAL
// variables — device.MessageInitiationType, MessageResponseType,
// MessageCookieReplyType, MessageTransportType. (*device.Device).IpcSet assigns
// them (in handlePostConfig) from a configured engine's profile, and
// (*device.Device).Close restores them to the WireGuard defaults (in
// resetProtocol) UNCONDITIONALLY — closing ANY engine, plain or configured,
// reverts the process-global message types to their defaults.
//
// Two consequences make a CONFIGURED (amnezia) engine require PROCESS
// EXCLUSIVITY:
//   - a second configured engine would overwrite the first engine's message-type
//     framing at IpcSet; and even with the SAME profile, closing the first engine
//     runs resetProtocol and reverts the globals to defaults under the second,
//     still-live engine, silently dropping its tunnel to plain-WireGuard framing.
//   - closing ANY other engine — a PLAIN (unconfigured) one included — runs
//     resetProtocol and resets the globals out from under a live configured engine.
//
// So the rule wanbond ASSERTS (rather than vendor-patching the fork) is:
//   - a configured engine may come up only when NO other engine is live, and
//   - no engine (plain or configured) may come up while a configured engine is live.
//
// PLAIN engines may coexist with each other: they never set the globals, and
// resetProtocol on their Close only restores the defaults they already use, so it
// is idempotent among them. wanbond runs exactly one tunnel per process, so the
// guard only ever trips on genuine misuse.
type amneziaGuard struct {
	mu         sync.Mutex
	plainLive  int  // number of live plain-WireGuard (unconfigured) engines
	configLive bool // whether a configured (amnezia) engine is live (at most one)
}

// globalAmneziaGuard enforces the single-amnezia-engine-per-process invariant for
// every Tunnel brought up in this process.
var globalAmneziaGuard amneziaGuard

// acquire registers an about-to-start engine against the process-exclusivity rule
// (see amneziaGuard). A configured (amnezia) engine is admitted only when NO other
// engine is live. A plain engine is admitted only when no configured engine is
// live; plain engines may coexist with one another. The caller must release the
// SAME profile exactly once when the engine is torn down (plain engines included —
// release is no longer a no-op for them).
func (g *amneziaGuard) acquire(a config.Amnezia) error {
	g.mu.Lock()
	defer g.mu.Unlock()
	if a.Configured() {
		if g.configLive || g.plainLive > 0 {
			return fmt.Errorf("device: refusing to start an amnezia-configured engine while another engine is live: " +
				"amneziawg-go keeps the magic-header message types in process-global state and resets them to defaults on ANY engine's Close, " +
				"so a configured engine requires process exclusivity — at most one, with no other engine alongside it (D2)")
		}
		g.configLive = true
		return nil
	}
	if g.configLive {
		return fmt.Errorf("device: refusing to start a second engine while an amnezia-configured engine is live: " +
			"closing this engine would reset amneziawg-go's process-global message types to defaults under the live amnezia tunnel (D2)")
	}
	g.plainLive++
	return nil
}

// release drops an engine's hold on the guard. A configured engine clears the
// single configured slot; a plain engine decrements the live plain count.
func (g *amneziaGuard) release(a config.Amnezia) {
	g.mu.Lock()
	defer g.mu.Unlock()
	if a.Configured() {
		g.configLive = false
		return
	}
	if g.plainLive > 0 {
		g.plainLive--
	}
}

// Up creates the TUN, wires the multipath Bind into the amneziawg engine,
// applies the crypto configuration from cfg, and brings the device up. The same
// path drives both roles; the role only changes which UAPI fields cfg carries
// (the concentrator sets listen_port; the edge sets each peer's endpoint).
func Up(cfg *config.Config, lg log.Logger) (*Tunnel, error) {
	clg := lg.Component("device")

	tunDev, err := tun.CreateTUN(defaultTUNName, tunMTU(cfg))
	if err != nil {
		return nil, fmt.Errorf("device: create TUN: %w", err)
	}
	name, err := tunDev.Name()
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: read TUN name: %w", err)
	}

	// Claim the single-amnezia-engine-per-process invariant (D2) BEFORE IpcSet
	// assigns amneziawg-go's process-global message-type state. On any failure
	// below, ok stays false and the deferred release returns the hold; the
	// successful path transfers the hold to the returned Tunnel.
	if err := globalAmneziaGuard.acquire(cfg.Amnezia); err != nil {
		_ = tunDev.Close()
		return nil, err
	}
	ok := false
	defer func() {
		if !ok {
			globalAmneziaGuard.release(cfg.Amnezia)
		}
	}()

	// One live *telemetry.Prober per path drives on-wire liveness. The SAME prober
	// values back the scheduler's PathHealth AND the bind's probe transport, so the
	// liveness the probe loop measures is exactly the liveness the scheduler selects
	// on (T37 replaces the sched.AlwaysUp placeholder here).
	scheduler, probers, newProber, err := buildScheduler(cfg, clg)
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: build scheduler: %w", err)
	}
	mpBind, err := bind.NewMultipath(cfg.Paths, cfg.PSK, scheduler, probers, newProber, fecConfig(cfg.FEC), adaptiveFECConfig(cfg.FEC), cfg.Amnezia)
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: build multipath bind: %w", err)
	}
	dev := awgdevice.NewDevice(tunDev, mpBind, engineLogger(clg, cfg.Log.Level))

	uapi, err := uapiConfig(cfg)
	if err != nil {
		dev.Close()
		return nil, fmt.Errorf("device: build UAPI config: %w", err)
	}
	if err := dev.IpcSet(uapi); err != nil {
		dev.Close()
		return nil, fmt.Errorf("device: apply UAPI config: %w", err)
	}
	if err := dev.Up(); err != nil {
		dev.Close()
		return nil, fmt.Errorf("device: bring up: %w", err)
	}

	// The engine has opened the bind (dev.Up → BindUpdate → Open), so the per-path
	// sockets exist: start the probe cadence now. Close stops it before dev.Close.
	// The interval is the SINGLE-SOURCE-OF-TRUTH telemetry default, which also arms
	// the bind's receive-path liveness sweep throttle (D15).
	stopProbes := mpBind.StartProbeLoop(telemetry.DefaultProbeInterval)
	// Start the background deferred-path reconciler alongside probing (T55): a path the
	// tolerant Open left DOWN (its source_addr not yet assignable — a 5G modem without a
	// lease at boot) is retried and promoted to a live path as its address appears,
	// WITHOUT a tunnel restart. Close stops it before dev.Close, like the probe loop.
	stopReconcile := mpBind.StartReconcileLoop(bind.DefaultReconcileInterval)
	// Start the edge-side hub-failover monitor (T57): on hub loss (every path to the
	// active concentrator DOWN) it advances to the next ordered peer endpoint, repoints the
	// bond's remote, and re-handshakes. A no-op on the concentrator, a single-concentrator
	// edge, or a bind without the probe transport. Started AFTER dev.Up so the engine peer
	// the re-handshake looks up exists (IpcSet added it above). Close stops it before
	// dev.Close, like the probe/reconcile loops.
	stopHubFailover := startHubFailover(cfg, mpBind, probers, dev, clg)

	t := &Tunnel{
		dev: dev, tun: tunDev, name: name, bind: mpBind, cfg: cfg, log: clg,
		stopProbes: stopProbes, stopReconcile: stopReconcile, stopHubFailover: stopHubFailover, amnezia: cfg.Amnezia,
		// The Source reads live per-path counters/telemetry from the Bind and derives
		// throughput from the byte-counter delta between scrapes (see metricsSource). It is
		// built unconditionally (cheap) so a reload that later turns [metrics].listen ON has
		// a Source ready; the endpoint itself is started only when a listen is configured.
		metricsSrc: newMetricsSource(mpBind, telemetry.SystemClock{}),
	}

	// Stand up the /metrics endpoint when configured. A non-loopback listen is refused
	// by metrics.NewServer (fail fast) — surface it as an Up failure rather than booting
	// a tunnel that silently exposes per-path operational data off-host.
	t.reloadMu.Lock()
	err = t.applyMetricsLocked(cfg.Metrics.Listen)
	t.reloadMu.Unlock()
	if err != nil {
		// The tunnel is fully constructed and holds the amnezia guard, so transfer that
		// ownership to it (ok=true) BEFORE tearing it down: t.Close releases the guard via
		// releaseOnce, and suppressing the !ok defer avoids a double release. t.Close also
		// stops the probe loop and closes the engine/TUN.
		ok = true
		t.Close()
		return nil, fmt.Errorf("device: start metrics endpoint: %w", err)
	}

	ok = true
	clg.Info("tunnel up", "interface", name, "role", string(cfg.Role))
	return t, nil
}

// applyMetricsLocked reconciles the running /metrics endpoint to listen: it starts the
// endpoint when one is desired and none runs, stops it when listen is empty, and rebinds
// (stop old, start new) when the address changed. It is idempotent for an unchanged
// address. The Source is reused across a rebind so its derived-throughput state is not
// reset. The caller MUST hold reloadMu (Up and Reload both do), which also serializes it
// against Close reading metricsSrv. On a NewServer/refuse error the previous server is
// left running untouched, so a bad reload never drops a working endpoint.
func (t *Tunnel) applyMetricsLocked(listen string) error {
	if listen == t.metricsListen {
		return nil
	}
	if listen == "" {
		t.stopMetricsLocked()
		return nil
	}
	srv, err := metrics.NewServer(listen, t.metricsSrc, t.log)
	if err != nil {
		return err
	}
	t.stopMetricsLocked()
	srv.Start()
	t.metricsSrv = srv
	t.metricsListen = listen
	return nil
}

// stopMetricsLocked gracefully shuts the running endpoint down (if any) and clears the
// bookkeeping. Caller holds reloadMu.
func (t *Tunnel) stopMetricsLocked() {
	if t.metricsSrv == nil {
		return
	}
	ctx, cancel := context.WithTimeout(context.Background(), metricsShutdownTimeout)
	defer cancel()
	if err := t.metricsSrv.Close(ctx); err != nil {
		t.log.Warn("metrics endpoint shutdown error", "error", err.Error())
	}
	t.metricsSrv = nil
	t.metricsListen = ""
}

// Reload applies a reloaded configuration to the RUNNING tunnel by diffing its
// path set against the live one and adding/removing paths at runtime (T30), WITHOUT
// tearing the tunnel down: the WG session, the surviving paths, and in-flight
// resequencing are all preserved. cfg is assumed already validated (config.Load
// fails fast on a bad file, so a bad reload never reaches here and never disturbs
// the running tunnel). Only the path set is diffed — the crypto/amnezia/role fields
// are fixed for the life of the process and a reload does not re-key the engine.
//
// New paths are added BEFORE absent ones are removed, so a failed addition aborts
// with every existing path still in service. Diffing is by name: a path present in
// both sets is left untouched (its source/dest parameters are not re-read).
//
// A membership-only reload CANNOT apply every kind of change: a same-name path whose
// source/dest changed, a path REORDER (index 0 is the preferred primary, so a reorder
// is a priority change), and every non-path field (psk, wireguard, amnezia, role, log,
// metrics) are all out of scope for T30. Rather than silently diverge from the file,
// Reload logs an EXPLICIT WARNING per ignored change (reloadWarnings) so the operator
// knows exactly what was dropped; only the path-membership add/remove is applied.
func (t *Tunnel) Reload(cfg *config.Config) error {
	t.reloadMu.Lock()
	defer t.reloadMu.Unlock()

	for _, w := range reloadWarnings(t.cfg, cfg) {
		t.log.Warn("reload: ignored config change (path-membership reload only)", "change", w)
	}

	// Rebind the /metrics endpoint if its listen address changed (T23). This is one of
	// the few non-path fields a reload DOES apply: the endpoint is external to the WG
	// session and the Bind, so restarting it disturbs neither. applyMetricsLocked reuses
	// the tunnel's stable Source (its derived-throughput state survives), and on a refuse
	// (e.g. a newly non-loopback address) leaves the previous endpoint running and fails
	// the reload — the running tunnel is never disturbed. Applied BEFORE the path diff so
	// a metrics-refuse aborts before any membership change.
	if cfg.Metrics.Listen != t.metricsListen {
		if err := t.applyMetricsLocked(cfg.Metrics.Listen); err != nil {
			return fmt.Errorf("device: reload metrics endpoint: %w", err)
		}
		t.log.Info("reload: metrics endpoint rebound", "listen", cfg.Metrics.Listen)
	}

	add, remove := diffPaths(t.bind.PathNames(), cfg.Paths)
	for _, def := range add {
		if err := t.bind.AddPath(def); err != nil {
			return fmt.Errorf("device: reload add path %q: %w", def.Name, err)
		}
		t.log.Info("reload: path added", "path", def.Name)
	}
	for _, name := range remove {
		if err := t.bind.RemovePath(name); err != nil {
			return fmt.Errorf("device: reload remove path %q: %w", name, err)
		}
		t.log.Info("reload: path removed", "path", name)
	}
	// Advance the running config to the membership now in service. Survivors keep their
	// ORIGINAL parameters and all non-path fields stay as booted (the ignored changes
	// were not applied), so a subsequent identical reload re-warns about a still-diverged
	// file rather than silently accepting it. Metrics.Listen is carried to the applied
	// value so a subsequent reload diffs against the endpoint actually running.
	t.cfg = runningConfig(t.cfg, add, remove)
	t.cfg.Metrics.Listen = t.metricsListen
	return nil
}

// reloadWarnings compares the desired config against the currently-running one and
// returns one human-readable warning per change a path-membership-only reload (T30)
// cannot apply: a modified same-name path (source/dest), a path reorder, and any
// non-path field. Membership add/remove is NOT reported here — it is applied. Full
// modify-support is out of scope; SILENCE is not — the operator must be told what was
// ignored. It is a pure function so the warning set is unit-testable.
func reloadWarnings(live, desired *config.Config) []string {
	var w []string

	if live.Role != desired.Role {
		w = append(w, fmt.Sprintf("role %q -> %q", live.Role, desired.Role))
	}
	if !reflect.DeepEqual(live.PSK, desired.PSK) {
		w = append(w, "psk changed")
	}
	if !reflect.DeepEqual(live.WireGuard, desired.WireGuard) {
		w = append(w, "wireguard section changed")
	}
	if !reflect.DeepEqual(live.Amnezia, desired.Amnezia) {
		w = append(w, "amnezia section changed")
	}
	if !reflect.DeepEqual(live.Log, desired.Log) {
		w = append(w, "log section changed")
	}
	// NOTE: a Metrics change is NOT warned here — unlike the other non-path fields, the
	// reload APPLIES it by rebinding the /metrics endpoint (see Reload). Warning about a
	// change that is honoured would misinform the operator.

	// Same-name paths whose parameters changed: diffPaths matches by name only, so a
	// modified source/dest on an existing path is otherwise silently dropped.
	liveByName := make(map[string]config.Path, len(live.Paths))
	for _, p := range live.Paths {
		liveByName[p.Name] = p
	}
	for _, d := range desired.Paths {
		l, ok := liveByName[d.Name]
		if !ok {
			continue // a genuinely new path is added, not ignored
		}
		if l.SourceAddr != d.SourceAddr || l.DestAddr != d.DestAddr {
			w = append(w, fmt.Sprintf("path %q source/dest changed — the running path keeps its original binding", d.Name))
		}
	}

	if reordered(live.Paths, desired.Paths) {
		w = append(w, "path priority order changed (reorder) — the running order is unchanged")
	}
	return w
}

// reordered reports whether the paths common to BOTH slices appear in a different
// relative order in desired than in live. The common subsequence has the same length
// on both sides (it is the name intersection), so a positional mismatch is a reorder.
func reordered(live, desired []config.Path) bool {
	desiredNames := make(map[string]struct{}, len(desired))
	for _, p := range desired {
		desiredNames[p.Name] = struct{}{}
	}
	liveNames := make(map[string]struct{}, len(live))
	for _, p := range live {
		liveNames[p.Name] = struct{}{}
	}
	var liveCommon, desiredCommon []string
	for _, p := range live {
		if _, ok := desiredNames[p.Name]; ok {
			liveCommon = append(liveCommon, p.Name)
		}
	}
	for _, p := range desired {
		if _, ok := liveNames[p.Name]; ok {
			desiredCommon = append(desiredCommon, p.Name)
		}
	}
	for i := range liveCommon {
		if liveCommon[i] != desiredCommon[i] {
			return true
		}
	}
	return false
}

// runningConfig advances the running config to the membership the bind now serves:
// the survivors (live paths not removed, keeping their ORIGINAL parameters and order)
// followed by the added paths (their new parameters). Non-path fields are carried over
// unchanged — a membership-only reload does not re-apply them. It mirrors the m.defs
// order the bind rebuilds on a Close→Open (survivors-in-order, then appended adds).
func runningConfig(live *config.Config, add []config.Path, remove []string) *config.Config {
	removeSet := make(map[string]struct{}, len(remove))
	for _, n := range remove {
		removeSet[n] = struct{}{}
	}
	paths := make([]config.Path, 0, len(live.Paths)+len(add))
	for _, p := range live.Paths {
		if _, gone := removeSet[p.Name]; !gone {
			paths = append(paths, p)
		}
	}
	paths = append(paths, add...)
	running := *live
	running.Paths = paths
	return &running
}

// diffPaths computes, by name, which desired paths are not yet live (to add) and
// which live paths are no longer desired (to remove). It is a pure function so the
// reload diff is unit-testable without a running engine.
func diffPaths(live []string, desired []config.Path) (add []config.Path, remove []string) {
	liveSet := make(map[string]struct{}, len(live))
	for _, n := range live {
		liveSet[n] = struct{}{}
	}
	desiredSet := make(map[string]struct{}, len(desired))
	for _, p := range desired {
		desiredSet[p.Name] = struct{}{}
		if _, ok := liveSet[p.Name]; !ok {
			add = append(add, p)
		}
	}
	for _, n := range live {
		if _, ok := desiredSet[n]; !ok {
			remove = append(remove, n)
		}
	}
	return add, remove
}

// defaultFailbackDwell is how long a recovered higher-priority path must stay up
// before egress fails BACK to it, damping flap-induced thrash (T15 hysteresis).
// Unlike the probe-cadence/liveness thresholds (which are the shared
// telemetry.Default* single source of truth, D16), the failback dwell is not part
// of the failover-recovery budget — failover to a backup is instant — so it stays a
// device-local constant.
const defaultFailbackDwell = 5 * time.Second

// fecConfig maps the validated [fec] config block onto the fec.Config the multipath
// Bind consumes (T24), or returns nil when FEC is disabled so the Bind runs the
// datapath with no parity plane. The ratio was already range-checked in config
// validation; the Bind re-validates defensively.
func fecConfig(f config.FEC) *fec.Config {
	if !f.Enabled {
		return nil
	}
	return &fec.Config{
		DataShards:   f.DataShards,
		ParityShards: f.ParityShards,
		Deadline:     f.Deadline,
	}
}

// adaptiveFECConfig maps the [fec] block onto the adaptive controller config the multipath
// Bind drives (T29), or returns nil when FEC is disabled or the block did not opt into
// adaptive mode — in which case the Bind runs the fixed-ratio plane (T24) unchanged. The
// controller uses the simulation-proven default control law (internal/adaptivefec,
// DefaultConfig), with only the group geometry pinned to the configured ratio: DataShards
// (K) is the FEC data_shards and MaxParity (the parity CEILING) is the FEC parity_shards,
// which the receiver's decoder is built at. The Bind re-validates and cross-checks these
// against the FEC config defensively.
func adaptiveFECConfig(f config.FEC) *adaptivefec.Config {
	if !f.Enabled || !f.Adaptive {
		return nil
	}
	c := adaptivefec.DefaultConfig()
	c.DataShards = f.DataShards
	c.MaxParity = f.ParityShards
	// Exactly one sizing mode is active (config load enforces mutual exclusion): in the
	// residual-SLA mode f.SafetyFactor is 0 and f.TargetResidual drives M; in the legacy
	// mode f.TargetResidual is 0 and f.SafetyFactor (defaulted at load) drives M.
	c.SafetyFactor = f.SafetyFactor
	c.TargetResidual = f.TargetResidual
	return &c
}

// buildScheduler constructs one live *telemetry.Prober per path and the P1
// active-backup send scheduler over them, in cfg.Paths' configured priority order
// (index 0 = the preferred primary). The returned probers ARE the scheduler's
// PathHealth sources (a *Prober is internally synchronized, satisfying the
// PathHealth concurrency contract — a bare *Liveness would not) and are handed to
// the bind so the probe transport drives the very same liveness the scheduler
// selects on. This replaces the T15 sched.AlwaysUp placeholder with real on-wire
// failover (T37).
func buildScheduler(cfg *config.Config, lg log.Logger) (sched.Scheduler, []*telemetry.Prober, bind.ProberFactory, error) {
	clock := telemetry.SystemClock{}
	proberCfg := telemetry.ProberConfig{
		LossWindow: telemetry.DefaultLossWindow,
		Liveness: telemetry.LivenessConfig{
			DownAfter:        telemetry.DefaultDownAfter,
			UpAfterSuccesses: telemetry.DefaultUpSuccesses,
		},
	}
	// One random per-boot session id shared by every path's Prober (it identifies
	// this boot, not the path): a peer restart presents a new session id that resets
	// the surviving responder's anti-replay high-water so liveness recovers (T38, D12).
	// A runtime-added path (T30) reuses the SAME session id, so its probes join this
	// boot's stream and the peer's reflector adopts them without a challenge reset.
	sessionID, err := telemetry.NewSessionID(rand.Reader)
	if err != nil {
		return nil, nil, nil, err
	}
	// newProber mints one path's Prober with the shared session/config/clock. It is
	// the single construction point for boot-time AND runtime paths, so both measure
	// liveness identically.
	newProber := func(name string, id uint8) *telemetry.Prober {
		return telemetry.NewProber(name, id, sessionID, cfg.PSK, proberCfg, clock, lg)
	}
	probers := make([]*telemetry.Prober, len(cfg.Paths))
	health := make([]sched.PathHealth, len(cfg.Paths))
	quality := make([]sched.PathQuality, len(cfg.Paths))
	for i := range cfg.Paths {
		probers[i] = newProber(cfg.Paths[i].Name, uint8(i))
		health[i] = probers[i]
		quality[i] = probers[i]
	}
	// Policy is a config choice: active-backup (P1, default) or the T21 weighted-
	// aggregation policy. Both consume the SAME per-path *Prober set — a *Prober
	// satisfies BOTH PathHealth (liveness) and PathQuality (RTT/loss Estimate) — so the
	// probe transport drives the very liveness/quality the scheduler selects on, and the
	// swap is behind config with no Bind change.
	scheduler, err := selectScheduler(cfg, health, quality, clock, lg)
	if err != nil {
		return nil, nil, nil, err
	}
	return scheduler, probers, newProber, nil
}

// selectScheduler builds the send scheduler the configured policy names, over the
// per-path health (and, for the weighted policy, quality) sources. active-backup is
// the P1 default; weighted is T21. The weighted knobs are validated at config load,
// so translating them here cannot fail on range — only NewWeighted's structural
// checks (which the wiring satisfies) apply.
func selectScheduler(cfg *config.Config, health []sched.PathHealth, quality []sched.PathQuality, clock telemetry.Clock, lg log.Logger) (sched.Scheduler, error) {
	switch cfg.Scheduler.Policy {
	case config.PolicyWeighted:
		sc := cfg.Scheduler
		return sched.NewWeighted(health, quality, sched.WeightedConfig{
			PerPathCapacity:   sc.PerPathCapacityFPS,
			EngageFraction:    sc.EngageFraction,
			DisengageFraction: sc.DisengageFraction,
			CollapseDwell:     sc.CollapseDwell,
			LoadTau:           sc.LoadTau,
			Pacing:            sc.PacingEnabled,
			PacingBurst:       sc.PacingBurstFrames,
			WeightRTTFloor:    sc.WeightRTTFloor,
			WeightLossFloor:   sc.WeightLossFloor,
		}, clock, lg)
	default:
		// active-backup (and the empty default, normalized to it at config load).
		return sched.NewActiveBackup(
			health,
			sched.Config{FailbackAfter: defaultFailbackDwell},
			clock,
			lg,
		)
	}
}

// Name is the created TUN interface name (for external addressing/routing).
func (t *Tunnel) Name() string { return t.name }

// Wait blocks until the device is torn down (its own Close, or an unrecoverable
// engine error).
func (t *Tunnel) Wait() { <-t.dev.Wait() }

// Close stops the probe loop, brings the device down, and releases the TUN and
// Bind. Idempotent. It also releases this tunnel's hold on the single-amnezia-
// engine-per-process guard exactly once, so a later Up may reconfigure the
// process-global amnezia state. Probing is stopped BEFORE the engine tears the
// bind's sockets down so no emission races the close.
func (t *Tunnel) Close() {
	// Shut the scrape endpoint FIRST so no in-flight /metrics scrape reads the Bind while
	// the engine tears its sockets down. reloadMu serializes this against a concurrent
	// SIGHUP-driven rebind.
	t.reloadMu.Lock()
	t.stopMetricsLocked()
	t.reloadMu.Unlock()
	if t.stopProbes != nil {
		t.stopProbes()
	}
	if t.stopReconcile != nil {
		t.stopReconcile()
	}
	if t.stopHubFailover != nil {
		t.stopHubFailover()
	}
	t.dev.Close()
	t.releaseOnce.Do(func() { globalAmneziaGuard.release(t.amnezia) })
}

// engineLogger adapts the amneziawg engine's logger onto wanbond's structured
// logger under a "wg" component. The engine is verbose only when the daemon runs
// at debug level; otherwise only its errors surface.
func engineLogger(lg log.Logger, level string) *awgdevice.Logger {
	wg := lg.Component("wg")
	verbosef := func(string, ...any) {}
	if strings.EqualFold(strings.TrimSpace(level), "debug") {
		verbosef = func(format string, args ...any) { wg.Debug(fmt.Sprintf(format, args...)) }
	}
	return &awgdevice.Logger{
		Verbosef: verbosef,
		Errorf:   func(format string, args ...any) { wg.Error(fmt.Sprintf(format, args...)) },
	}
}

// uapiConfig renders cfg into the newline-delimited UAPI set string the engine's
// IpcSet consumes. Keys are lowercase hex (UAPI's on-the-wire encoding), NOT the
// base64 form the TOML carries. Amnezia obfuscation keys are emitted only when the
// block is configured; an all-zero Amnezia block leaves the engine in plain
// WireGuard mode. The same amnezia parameters are applied on BOTH roles (edge and
// concentrator) as defense-in-depth — they must match end to end for the handshake
// to succeed (config validation makes each end specify a complete profile, D1).
func uapiConfig(cfg *config.Config) (string, error) {
	var b strings.Builder

	priv := cfg.WireGuard.PrivateKey.Bytes()
	fmt.Fprintf(&b, "private_key=%s\n", hex.EncodeToString(priv[:]))
	if cfg.Role == config.RoleConcentrator {
		fmt.Fprintf(&b, "listen_port=%d\n", cfg.WireGuard.ListenPort)
	}
	writeAmnezia(&b, cfg.Amnezia)

	for i, peer := range cfg.WireGuard.Peers {
		pub := peer.PublicKey.Bytes()
		fmt.Fprintf(&b, "public_key=%s\n", hex.EncodeToString(pub[:]))
		if len(peer.Endpoints) > 0 {
			// Endpoints[0] is the active/primary concentrator (Q18 ordered-endpoint
			// active-standby); it is populated from either the legacy single
			// `endpoint` field or the new ordered `endpoints` list (config.Peer.
			// resolveEndpoints), so both forms bring up the tunnel identically here.
			// Switching to a standby endpoint on hub loss is T57's job, not this
			// initial UAPI render.
			fmt.Fprintf(&b, "endpoint=%s\n", peer.Endpoints[0])
			// A keepalive keeps the edge->concentrator session warm and lets the
			// concentrator relearn the edge endpoint after a NAT rebind; only the
			// initiating (edge) side sets it.
			fmt.Fprintf(&b, "persistent_keepalive_interval=%d\n", keepaliveSeconds)
		}
		if len(peer.AllowedIPs) == 0 {
			return "", fmt.Errorf("peer %d (%s): at least one allowed_ip is required", i, hex.EncodeToString(pub[:8]))
		}
		for _, cidr := range peer.AllowedIPs {
			fmt.Fprintf(&b, "allowed_ip=%s\n", cidr)
		}
	}
	return b.String(), nil
}

// keepaliveSeconds is the edge's persistent-keepalive interval.
const keepaliveSeconds = 25

// writeAmnezia emits the nine amneziawg obfuscation UAPI keys, but only when the
// block is configured. When amnezia is unused, wanbond leaves the engine's
// PROCESS-GLOBAL message-type state untouched (see the amneziaGuard invariant).
// Config validation guarantees a configured block is complete and self-consistent
// (D1), and applyDefaults has already filled the standard magic headers (1..4)
// when they were omitted, so the emitted set never carries an h*=0 sentinel.
func writeAmnezia(b *strings.Builder, a config.Amnezia) {
	if !a.Configured() {
		return
	}
	fmt.Fprintf(b, "jc=%d\njmin=%d\njmax=%d\ns1=%d\ns2=%d\nh1=%d\nh2=%d\nh3=%d\nh4=%d\n",
		a.Jc, a.Jmin, a.Jmax, a.S1, a.S2, a.H1, a.H2, a.H3, a.H4)
}

package device

import (
	"net/netip"
	"sync"
	"time"

	awgdevice "github.com/amnezia-vpn/amneziawg-go/device"

	"github.com/7mind/wanbond/internal/bind"
	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/telemetry"
)

// hubFailoverSettle is the dwell a newly-selected concentrator endpoint is given to
// prove itself LIVE before the controller may advance again. It exists to keep a
// STILL-DOWN reading — caused merely by echoes not having returned from the just-
// selected hub yet — from skipping straight past a healthy standby.
//
// It must comfortably exceed the liveness UP-recovery latency: a DOWN path comes UP
// after telemetry.DefaultUpSuccesses (3) probe echoes at telemetry.DefaultProbeInterval
// (200ms) ≈ 600ms once probes reach a reachable hub. At 3s the dwell clears that with a
// wide margin for jitter/RTT, and also bounds the re-advance cadence while a whole hub
// fleet is down to at most one switch (one fresh handshake) per 3s. Hub loss is a
// coarse, rare event (a concentrator down), distinct from the sub-second PER-PATH
// failover the schedulers own, so a switch latency on this scale is acceptable.
const hubFailoverSettle = 3 * time.Second

// hubHealth is one path's liveness verdict, the read side of the T13 telemetry state
// machine (*telemetry.Prober satisfies it). The hub-failover controller reads exactly
// the same up/down verdict the schedulers select on, so "hub loss" is derived from the
// very liveness plane per-path failover already runs on — no second detector.
type hubHealth interface {
	State() telemetry.PathState
}

// peerRemote repoints the whole bond's wire remote at a new concentrator endpoint
// (*bind.Multipath satisfies it via SetPeerRemote). It is the action half of a hub
// switch on the DATA/PROBE plane; the re-handshake is separate (rehandshake).
type peerRemote interface {
	SetPeerRemote(ap netip.AddrPort)
}

// rehandshake drops the current WireGuard session and initiates a FRESH one against the
// peer's static key — no hub-to-hub state handoff. The device wires it to the engine
// peer (expire keypairs + send handshake initiation); a test injects a counter.
type rehandshake func()

// hubFailover is the edge-side active-standby concentrator failover controller (Q18/T57).
// It watches the per-path liveness plane and, when EVERY path to the currently-active
// concentrator is DOWN simultaneously (HUB LOSS — distinct from a single path failing,
// which the schedulers already absorb), advances to the next endpoint in the ordered
// concentrator list, repoints every path's remote at it, and initiates a fresh WG
// re-handshake. It re-arms against the new endpoint and, if that one is also fully down,
// advances again.
//
// End-of-list policy: WRAP (round-robin modulo the list length). Once the last standby
// is exhausted the controller cycles back to index 0 and keeps retrying every endpoint
// in order. Wrap is chosen over stop because it preserves availability — a concentrator
// that RECOVERS earlier in the list is retried and settled on within one full cycle,
// whereas stopping at the last endpoint would strand the edge on a dead hub even after
// endpoint 0 came back. The settle dwell bounds the churn to one switch (one handshake)
// per hubFailoverSettle while the whole fleet is down, so the round-robin is a slow,
// bounded retry, not a storm.
//
// GUARD (must-hold invariant): a SINGLE-endpoint list takes NO failover action at all —
// check returns immediately, so the remote is never repointed and no re-handshake is
// initiated. A one-concentrator deployment therefore behaves EXACTLY as it did before
// T57 (the endpoints-list "list" is the one-element normalization of the legacy single
// endpoint form, per T54).
type hubFailover struct {
	// specs is the ORDERED concentrator endpoint set, one failoverSpec per configured
	// endpoint entry (config.Peer.EndpointSpecs), in TOML order. Each spec OWNS its
	// current expansion ([]netip.AddrPort): a literal is a fixed single entry; a hostname
	// is its latest resolved record set (empty until the resolver — wired by a later task —
	// first calls updateResolution). The FLATTENED concatenation of every spec's expansion,
	// in spec order, is the failover order; the flattened index is what `check` advances.
	// The set is MUTABLE: updateResolution swaps a spec's expansion in place under mu.
	specs []failoverSpec
	// health is the per-path liveness, one entry per configured path. Immutable after
	// construction (the prober set is fixed for the tunnel's life).
	health []hubHealth

	remote      peerRemote
	rehandshake rehandshake
	clock       telemetry.Clock
	// settle is the dwell a freshly-selected endpoint gets before another advance is
	// allowed (hubFailoverSettle in production; a test injects its own).
	settle time.Duration
	log    log.Logger

	mu sync.Mutex
	// activeSpec and activeAddr are the SPEC-SCOPED identity of the ACTIVE endpoint (R70):
	// the pair (owning spec index, AddrPort) — NEVER a bare flattened index and NEVER a
	// bare AddrPort. Because a hostname may legitimately re-resolve onto the SAME AddrPort
	// as another spec's literal (T67's load-time duplicate check is textual host:port
	// only), duplicate AddrPort VALUES may appear across different specs in the flattened
	// list; a bare-value re-map could silently bind the active pointer to the wrong spec's
	// entry, so the active endpoint is addressed by (specIdx, AddrPort). activeSpec == -1
	// means no active entry yet (every spec's expansion is empty). Guarded by mu.
	activeSpec int
	activeAddr netip.AddrPort
	// idx is the ACTIVE endpoint's position in the FLATTENED list, DERIVED from
	// (activeSpec, activeAddr) and re-mapped after every mutation. It is a read-only cache
	// for observation/logging; the source of truth is the spec-scoped identity above. -1
	// when there is no active entry. Guarded by mu.
	idx int
	// lastSwitch is when the active endpoint was last (re)selected — initialized to
	// construction time so endpoint 0 gets the SAME settle grace at boot that a switched
	// endpoint gets, preventing a boot-time false failover while probers are still DOWN
	// before the first echo returns. Guarded by mu.
	lastSwitch time.Time
}

// failoverSpec is one ordered endpoint entry together with its CURRENT expansion. A
// literal entry's expansion is the fixed single AddrPort; a hostname entry's expansion is
// its latest resolved record set (Q32 multi-record), swapped in place by updateResolution.
// The spec itself (config.EndpointSpec) is retained so the controller can tell a hostname
// spec — which may grow/shrink at runtime — from an immutable literal, e.g. when deciding
// whether the failover loop may ever have work to do.
type failoverSpec struct {
	spec  config.EndpointSpec
	addrs []netip.AddrPort
}

// newHubFailover builds the controller over an ordered list of IP-LITERAL endpoints — the
// legacy all-literal form (each address becomes its own single-entry literal spec). It is
// a pure constructor (no goroutine, no engine dependency beyond the injected collaborators)
// so its decision logic is unit-testable against a fake clock, fake health, and fake
// remote/rehandshake.
func newHubFailover(endpoints []netip.AddrPort, health []hubHealth, remote peerRemote, rh rehandshake, clock telemetry.Clock, settle time.Duration, lg log.Logger) *hubFailover {
	specs := make([]failoverSpec, len(endpoints))
	for i, ap := range endpoints {
		specs[i] = failoverSpec{spec: config.EndpointSpec{Addr: ap}, addrs: []netip.AddrPort{ap}}
	}
	return newHubFailoverFromSpecs(specs, health, remote, rh, clock, settle, lg)
}

// newHubFailoverFromSpecs builds the controller over the ordered, spec-keyed endpoint set.
// The active endpoint is initialized to the FIRST flattened entry (spec order); when every
// spec's expansion is empty (e.g. a hostname-only peer before the resolver has run) there
// is no active entry yet (activeSpec == -1) and check takes no action until an expansion
// appears. Like newHubFailover it injects no goroutine or engine dependency.
func newHubFailoverFromSpecs(specs []failoverSpec, health []hubHealth, remote peerRemote, rh rehandshake, clock telemetry.Clock, settle time.Duration, lg log.Logger) *hubFailover {
	h := &hubFailover{
		specs:       specs,
		health:      health,
		remote:      remote,
		rehandshake: rh,
		clock:       clock,
		settle:      settle,
		lastSwitch:  clock.Now(),
		log:         lg,
	}
	h.activeSpec, h.activeAddr = h.entryAtLocked(0)
	h.idx = h.flatIndexLocked(h.activeSpec, h.activeAddr)
	return h
}

// flatLenLocked is the number of endpoints in the FLATTENED list (the sum of every spec's
// current expansion length). Caller holds mu.
func (h *hubFailover) flatLenLocked() int {
	n := 0
	for i := range h.specs {
		n += len(h.specs[i].addrs)
	}
	return n
}

// canFailoverLocked reports whether the controller could EVER take a failover action: the
// flattened list already holds >= 2 endpoints, or SOME spec is a hostname whose runtime
// resolution may yet grow it. An all-literal set with a single entry can never grow, so its
// loop is a pure no-op and need not run. Caller holds mu.
func (h *hubFailover) canFailoverLocked() bool {
	if h.flatLenLocked() >= 2 {
		return true
	}
	for i := range h.specs {
		if h.specs[i].spec.IsName {
			return true
		}
	}
	return false
}

// flatIndexLocked returns the position of (specIdx, addr) in the FLATTENED list, or -1 if
// no such entry exists. It matches BOTH the owning spec index AND the AddrPort — never the
// bare value — so a duplicate AddrPort contributed by a DIFFERENT spec is skipped (R70);
// within the owning spec the FIRST occurrence wins. Caller holds mu.
func (h *hubFailover) flatIndexLocked(specIdx int, addr netip.AddrPort) int {
	flat := 0
	for si := range h.specs {
		for _, a := range h.specs[si].addrs {
			if si == specIdx && a == addr {
				return flat
			}
			flat++
		}
	}
	return -1
}

// entryAtLocked maps a FLATTENED index back to its (owning spec index, AddrPort), or
// (-1, zero) when flatIdx is out of range (including an empty flattened list). Caller holds mu.
func (h *hubFailover) entryAtLocked(flatIdx int) (int, netip.AddrPort) {
	if flatIdx < 0 {
		return -1, netip.AddrPort{}
	}
	n := 0
	for si := range h.specs {
		for _, a := range h.specs[si].addrs {
			if n == flatIdx {
				return si, a
			}
			n++
		}
	}
	return -1, netip.AddrPort{}
}

// containsAddrPort reports whether addrs holds target (exact AddrPort equality).
func containsAddrPort(addrs []netip.AddrPort, target netip.AddrPort) bool {
	for _, a := range addrs {
		if a == target {
			return true
		}
	}
	return false
}

// updateResolution swaps specIdx's expansion under h.mu — the sole mutation point of the
// endpoint set — and reconciles the active pointer WITHIN its owning spec (R70 spec-scoped
// identity):
//   - BOOT ADOPTION (activeSpec == -1: every spec's expansion was empty, e.g. a hostname-
//     only peer before the resolver first ran): the first resolution that makes the
//     flattened list non-empty ADOPTS its head as the active endpoint — set (activeSpec,
//     activeAddr), point the bond via exactly ONE SetPeerRemote, one rehandshake, and ARM
//     the settle dwell (lastSwitch = now). Without this a single-hostname peer's bond would
//     never receive any endpoint: check cannot rescue it either, because a one-record
//     expansion keeps the flattened length at 1, permanently under check's total<2 guard.
//   - A STANDBY-only change (specIdx != activeSpec) NEVER touches the bond: the active
//     entry is untouched; only the DERIVED flattened idx is re-mapped (an earlier spec
//     growing/shrinking shifts the active entry's flattened position without moving it).
//   - When the ACTIVE spec's own expansion changes: if the active AddrPort SURVIVES the
//     swap within that spec, the active entry is stable — strictly NO repoint (Q31/D32
//     no-op suppression), only the idx re-maps. If the active AddrPort is GONE, the active
//     endpoint's IP has genuinely changed: repoint via exactly ONE SetPeerRemote (D32
//     disruptive → Rebaseline + rehandshake) and one rehandshake to the new expansion's
//     first entry, and RE-ARM the settle dwell (lastSwitch = now) so the freshly-repointed
//     endpoint gets its full grace before a subsequent all-down check may advance off it.
//
// A change that empties the active spec (nothing to point at) leaves the active identity
// stale — the flattened list no longer contains it — and the next check on hub loss
// advances off it; no repoint is issued to a non-existent endpoint.
func (h *hubFailover) updateResolution(specIdx int, addrs []netip.AddrPort) {
	h.mu.Lock()
	defer h.mu.Unlock()

	if specIdx < 0 || specIdx >= len(h.specs) {
		return
	}
	h.specs[specIdx].addrs = addrs

	switch {
	case h.activeSpec == -1:
		// No active entry yet (every spec was empty at boot). If this resolution populated
		// the flattened list, adopt its head, point the bond at it, and arm the settle dwell.
		if adoptSpec, adoptAddr := h.entryAtLocked(0); adoptSpec != -1 {
			h.activeSpec = adoptSpec
			h.activeAddr = adoptAddr
			h.lastSwitch = h.clock.Now()
			h.remote.SetPeerRemote(adoptAddr)
			if h.rehandshake != nil {
				h.rehandshake()
			}
			h.log.Warn("hub failover: first endpoint resolution; adopted active concentrator endpoint and re-handshaked",
				"spec_index", adoptSpec, "to_endpoint", adoptAddr.String())
		}
	case specIdx == h.activeSpec:
		if !containsAddrPort(addrs, h.activeAddr) && len(addrs) > 0 {
			// The active endpoint's own spec re-resolved off the current AddrPort: its IP
			// changed. Repoint the bond once, re-handshake against the new first entry, and
			// re-arm the settle dwell against the freshly-repointed endpoint.
			prev := h.activeAddr
			h.activeAddr = addrs[0]
			h.lastSwitch = h.clock.Now()
			h.remote.SetPeerRemote(h.activeAddr)
			if h.rehandshake != nil {
				h.rehandshake()
			}
			h.log.Warn("hub failover: active concentrator endpoint re-resolved; repointed remote and re-handshaked",
				"spec_index", specIdx, "from_endpoint", prev.String(), "to_endpoint", h.activeAddr.String())
		}
		// Survived (or empty expansion): no repoint. idx re-maps below.
	}

	h.idx = h.flatIndexLocked(h.activeSpec, h.activeAddr)
}

// allPathsDown reports HUB LOSS — every path to the active concentrator DOWN — under h.mu.
// It is the read half of the coordination surface the re-resolution controller (T73) shares
// with the failover controller (Q34): the resolver reads the SAME liveness sweep the failover
// loop advances on, so a liveness-loss out-of-band re-resolve and a hub-loss advance derive
// from one detector, never two that could disagree.
func (h *hubFailover) allPathsDown() bool {
	h.mu.Lock()
	defer h.mu.Unlock()
	return h.allDownLocked()
}

// activeSpecIndex returns the owning spec index of the currently-active endpoint under h.mu,
// or -1 when there is no active entry yet (every spec's expansion empty). The re-resolution
// controller (T73) reads it to know WHICH spec a liveness-loss trigger must re-resolve out of
// band; the identity is spec-scoped (R70), so this is the spec index, never a flattened index.
func (h *hubFailover) activeSpecIndex() int {
	h.mu.Lock()
	defer h.mu.Unlock()
	return h.activeSpec
}

// allDownLocked reports HUB LOSS: every path's liveness to the active concentrator is
// DOWN simultaneously. An empty health set is NOT hub loss (there is nothing to declare
// dead — a bind without the probe transport never drives this). Caller holds mu.
func (h *hubFailover) allDownLocked() bool {
	if len(h.health) == 0 {
		return false
	}
	for _, hp := range h.health {
		if hp.State() != telemetry.StateDown {
			return false
		}
	}
	return true
}

// check is one failover-evaluation step: on confirmed hub loss (and once the active
// endpoint's settle dwell has elapsed) it advances to the next endpoint, repoints the
// bond's remote, and initiates a fresh re-handshake. It is idempotent and cheap in the
// steady state (any path up, or a single-endpoint list) — a length check plus a liveness
// sweep — so a periodic loop may call it at the probe cadence.
func (h *hubFailover) check() {
	h.mu.Lock()
	defer h.mu.Unlock()

	// GUARD: a FLATTENED list of fewer than two endpoints takes NO failover action — no
	// advance, no remote repoint, no re-handshake — so a one-concentrator deployment is
	// byte-for-byte the pre-T57 behaviour, and a hostname peer whose resolution has not yet
	// yielded a second endpoint waits rather than churning.
	total := h.flatLenLocked()
	if total < 2 {
		return
	}
	if !h.allDownLocked() {
		return
	}
	// Settle dwell: give the currently-active endpoint time for its liveness to recover
	// before advancing, so a not-yet-echoed (transiently DOWN) healthy endpoint is not
	// skipped. Applies at boot (endpoint 0) and after every switch.
	now := h.clock.Now()
	if now.Sub(h.lastSwitch) < h.settle {
		return
	}

	// Advance in FLATTENED order from the active entry's current flattened position. The
	// position is re-derived from the spec-scoped identity every step, so a standby spec
	// that grew/shrank since the last advance is walked at its new offset. A missing active
	// (activeSpec == -1, or its AddrPort no longer present) resumes from the head.
	prev := h.flatIndexLocked(h.activeSpec, h.activeAddr)
	var nextIdx int
	if prev < 0 {
		nextIdx = 0
	} else {
		nextIdx = (prev + 1) % total
	}
	nextSpec, next := h.entryAtLocked(nextIdx)
	h.activeSpec = nextSpec
	h.activeAddr = next
	h.idx = nextIdx
	h.lastSwitch = now

	// Repoint the DATA/PROBE plane FIRST so probes immediately start re-arming detection
	// against the new endpoint, then initiate the fresh WG re-handshake toward it.
	h.remote.SetPeerRemote(next)
	if h.rehandshake != nil {
		h.rehandshake()
	}
	h.log.Warn("hub failover: all paths to active concentrator down; switched endpoint and re-handshaked",
		"from_index", prev, "to_index", nextIdx, "to_spec", nextSpec, "to_endpoint", next.String(), "endpoints", total)
}

// deviceRehandshake returns a rehandshake bound to the engine peer identified by pk: it
// EXPIRES the peer's current keypairs (dropping the old hub's session — a fresh session
// with NO hub-to-hub state handoff) and sends a fresh handshake initiation, which the
// Bind fans out to the just-repointed standby endpoint. All hubs in the ordered set
// share the peer's single WireGuard static key, so the SAME peer identity re-handshakes
// against whichever hub is now active. A peer the engine cannot resolve (never configured
// — impossible for the edge's sole peer) yields a no-op so the loop never dereferences
// nil. This is the ONLY engine-peer coupling the failover path takes; it stays in the
// device package alongside the rest of the engine wiring.
func deviceRehandshake(dev *awgdevice.Device, pk config.Key) rehandshake {
	key := awgdevice.NoisePublicKey(pk.Bytes())
	return func() {
		peer := dev.LookupPeer(key)
		if peer == nil {
			return
		}
		// Drop the current session so the re-handshake starts a FRESH keypair (no hub-to-hub
		// handoff); ExpireCurrentKeypairs also backdates lastSentHandshake so the immediately
		// following initiation is not suppressed by the RekeyTimeout guard.
		peer.ExpireCurrentKeypairs()
		_ = peer.SendHandshakeInitiation(false)
	}
}

// peerNeedsHubFailover reports whether a peer's endpoint set warrants a hub-failover
// controller: it does when the peer carries ANY hostname spec (its runtime resolution may
// yield further endpoints, and even a single hostname can re-resolve onto a new IP the bond
// must be repointed at) OR when >= 2 IP-literal endpoints are configured (an ordered
// active-standby list). A single-IP-literal peer needs NO controller — it is byte-for-byte
// the pre-G5 single-concentrator deployment (Q29), so the failover path never constructs
// or runs for it.
func peerNeedsHubFailover(peer config.Peer) bool {
	for _, s := range peer.EndpointSpecs {
		if s.IsName {
			return true
		}
	}
	return len(peer.Endpoints) >= 2
}

// startHubFailover builds and starts the edge-side hub-failover monitor for cfg's
// concentrator peer, or returns a NO-OP stopper when hub failover does not apply: the
// concentrator role (it roams edges dynamically and has no endpoint list), a bind without
// the probe transport (no probers → no liveness plane), or no peer whose endpoint set
// warrants a controller (peerNeedsHubFailover — a single-IP-literal deployment gets none,
// staying behaviour-identical to pre-G5). The edge bonds every path to a SINGLE
// concentrator, so the whole per-path prober set IS the liveness of the paths to that
// concentrator (hub loss = every one DOWN); the controller drives the first qualifying
// peer. The returned stopper is what device.Close invokes to halt the loop.
func startHubFailover(cfg *config.Config, mp *bind.Multipath, probers []*telemetry.Prober, dev *awgdevice.Device, lg log.Logger) func() {
	if cfg.Role != config.RoleEdge || len(probers) == 0 {
		return func() {}
	}
	for _, peer := range cfg.WireGuard.Peers {
		if !peerNeedsHubFailover(peer) {
			continue
		}
		health := make([]hubHealth, len(probers))
		for i, pr := range probers {
			health[i] = pr
		}
		// Seed each spec's expansion: a literal is its fixed single AddrPort; a hostname
		// starts EMPTY — resolution is a later task's job (Q30), not wired here.
		specs := make([]failoverSpec, len(peer.EndpointSpecs))
		for i, s := range peer.EndpointSpecs {
			var addrs []netip.AddrPort
			if !s.IsName {
				addrs = []netip.AddrPort{s.Addr}
			}
			specs[i] = failoverSpec{spec: s, addrs: addrs}
		}
		ctrl := newHubFailoverFromSpecs(
			specs, health, mp,
			deviceRehandshake(dev, peer.PublicKey),
			telemetry.SystemClock{}, hubFailoverSettle,
			lg.Component("hubfailover"),
		)
		// Poll at the probe cadence: check is cheap (a length check plus a liveness sweep)
		// and the settle dwell bounds actual switches, so a responsive poll only tightens
		// detection latency without churning the remote.
		stopFailover := ctrl.startHubFailoverLoop(telemetry.DefaultProbeInterval)
		// Alongside failover, start the re-resolution controller (T73) over the SAME ctrl for a
		// peer carrying hostname specs: it re-resolves each on the [dns] poll cadence and out-of-
		// band on hub loss, feeding fresh records through ctrl.updateResolution (Q34 — the two
		// coordinate purely through the shared lock and update API). An all-literal peer has no
		// hostname to track, so it starts nothing.
		stopResolution := startResolution(cfg, ctrl, peer, lg)
		return func() {
			stopFailover()
			stopResolution()
		}
	}
	return func() {}
}

// startResolution builds and starts the re-resolution controller for peer's hostname endpoint
// specs over the already-constructed hub-failover controller, or returns a no-op stopper when the
// peer carries no hostname spec (an all-literal peer never re-resolves). The resolver transport is
// the one the (validated) [dns] block selects; a resolver-construction failure is logged and
// resolution is skipped rather than failing tunnel bring-up, since hub failover itself is
// independent of re-resolution.
func startResolution(cfg *config.Config, ctrl *hubFailover, peer config.Peer, lg log.Logger) func() {
	targets := nameTargetsFromSpecs(peer.EndpointSpecs)
	if len(targets) == 0 {
		return func() {}
	}
	resolver, err := cfg.DNS.NewResolver()
	if err != nil {
		lg.Warn("dns re-resolution: could not build resolver; hostname endpoints will not re-resolve",
			"error", err.Error())
		return func() {}
	}
	res := newResolution(
		resolver, ctrl, targets, pathFamiliesFromPaths(cfg.Paths),
		telemetry.SystemClock{}, cfg.DNS.PollInterval, cfg.DNS.Timeout,
		lg.Component("dnsresolve"),
	)
	// Drive step at the probe cadence: step is cheap in the steady state (a liveness read plus a
	// clock compare) and gates the actual poll on the [dns] poll interval internally, so a
	// responsive tick only tightens the liveness-loss re-resolve latency without over-resolving.
	return res.startResolutionLoop(telemetry.DefaultProbeInterval)
}

// startHubFailoverLoop launches the failover-evaluation goroutine: it calls check every
// interval until the returned stopper is invoked (idempotent). It mirrors the bind's
// StartProbeLoop/StartReconcileLoop lifecycle glue — a wall-clock ticker driving a
// decision function whose every timing choice runs through the injected Clock, so a test
// drives check directly against a fake clock and never starts this goroutine. It is a
// no-op (no-op stopper) for a controller that can NEVER fail over (canFailoverLocked: an
// all-literal set with fewer than two entries — no hostname to grow it) or a non-positive
// interval. A hostname peer whose expansion is still empty DOES start the loop: its
// resolution may later populate a second endpoint, and check no-ops cheaply until then.
func (h *hubFailover) startHubFailoverLoop(interval time.Duration) (stop func()) {
	h.mu.Lock()
	can := h.canFailoverLocked()
	h.mu.Unlock()
	if !can || interval <= 0 {
		return func() {}
	}
	done := make(chan struct{})
	go func() {
		ticker := time.NewTicker(interval)
		defer ticker.Stop()
		for {
			select {
			case <-done:
				return
			case <-ticker.C:
				h.check()
			}
		}
	}()
	var once sync.Once
	return func() { once.Do(func() { close(done) }) }
}

