54	const testSettle = 3 * time.Second
55	
56	// TestHubFailoverSwitchesOnHubLoss is the core acceptance: with a 2-endpoint list,
57	// forcing ALL paths to endpoint#1 DOWN switches the peer remote to endpoint#2 AND
58	// initiates exactly one re-handshake — while ANY path being UP takes no action at all
59	// (hub loss = EVERY path down, distinct from a single path failing).
60	func TestHubFailoverSwitchesOnHubLoss(t *testing.T) {
61		eps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820")
62		hp := []hubHealth{&fakeHealth{telemetry.StateUp}, &fakeHealth{telemetry.StateUp}}
63		rem := &recordingRemote{}
64		handshakes := 0
65		clk := &fakeClock{now: time.Unix(1000, 0)}
66		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
67	
