69		clk.advance(10 * time.Second)
70		h.check()
71		if rem.calls != 0 || handshakes != 0 {
72			t.Fatalf("failover fired while a path was UP: remote switches=%d handshakes=%d", rem.calls, handshakes)
73		}
74		if h.idx != 0 {
