124	// TestHubFailoverSingleEndpointNoAction is the GUARD: a SINGLE-endpoint list must take
125	// NO failover action even under sustained hub loss — no remote switch, no re-handshake,
126	// no index movement — so a one-concentrator deployment behaves EXACTLY as pre-T57. It is
127	// non-vacuous: absent the len<2 guard, the wrap arithmetic (0+1)%1==0 would "switch" to
128	// the same endpoint and fire a re-handshake, which this asserts never happens.
129	func TestHubFailoverSingleEndpointNoAction(t *testing.T) {
130		eps := mustEndpoints(t, "203.0.113.1:51820")
131		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
132		rem := &recordingRemote{}
133		handshakes := 0
134		clk := &fakeClock{now: time.Unix(1000, 0)}
135		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
136	
137		for i := 0; i < 5; i++ {
138			clk.advance(time.Minute)
139			h.check()
140		}
141		if rem.calls != 0 {
142			t.Fatalf("single-endpoint list switched the remote %d times, want 0", rem.calls)
143		}
144		if handshakes != 0 {
145			t.Fatalf("single-endpoint list re-handshaked %d times, want 0", handshakes)
146		}
147		if h.idx != 0 {
148			t.Fatalf("single-endpoint list moved active index to %d, want 0", h.idx)
149		}
150	}
