152	// TestHubFailoverReArmsAndWraps proves detection re-arms against the NEW active endpoint
153	// and, at the end of the list, WRAPS to index 0 (the documented end-of-list policy). With
154	// a 2-endpoint list held fully DOWN, successive settle-separated checks advance 0→1→0.
155	func TestHubFailoverReArmsAndWraps(t *testing.T) {
156		eps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820")
157		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
158		rem := &recordingRemote{}
159		handshakes := 0
160		clk := &fakeClock{now: time.Unix(1000, 0)}
161		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
162	
163		// First advance: 0 → 1 (settle since construction has elapsed).
164		clk.advance(testSettle + time.Second)
165		h.check()
166		if h.idx != 1 || rem.last != eps[1] || rem.calls != 1 {
167			t.Fatalf("first advance: idx=%d last=%v calls=%d, want idx=1 last=%v calls=1", h.idx, rem.last, rem.calls, eps[1])
168		}
169	
170		// Re-arm on the new endpoint, still fully down: after another settle, wrap 1 → 0.
171		clk.advance(testSettle + time.Second)
172		h.check()
173		if h.idx != 0 || rem.last != eps[0] || rem.calls != 2 {
174			t.Fatalf("wrap advance: idx=%d last=%v calls=%d, want idx=0 last=%v calls=2 (wrap to index 0)", h.idx, rem.last, rem.calls, eps[0])
175		}
176		if handshakes != 2 {
177			t.Fatalf("re-handshakes=%d, want 2 (one per advance)", handshakes)
178		}
179	}
