514	// TestHubFailoverCrossSpecDuplicateNoSpuriousReMap is acceptance (6), the R70 case: a
515	// hostname STANDBY spec re-resolving onto the SAME AddrPort as the active spec's own literal
516	// must NOT move the active pointer (spec-scoped identity, not bare value) and must not touch
517	// the bond; a subsequent hub-loss advance then walks the FLATTENED order correctly past the
518	// duplicate rather than being confused by it.
519	func TestHubFailoverCrossSpecDuplicateNoSpuriousReMap(t *testing.T) {
520		dup := mustAP(t, "203.0.113.1:51820")   // shared AddrPort across specs 0 and 1
521		tail := mustAP(t, "198.51.100.7:51820") // spec 2 literal standby
522		specs := []failoverSpec{
523			nameSpec("shadow.example.com", 51820), // spec 0: hostname, EMPTY at boot
524			litSpec(t, "203.0.113.1:51820"),       // spec 1: literal dup → boot-active (flat[0])
525			litSpec(t, "198.51.100.7:51820"),      // spec 2: literal standby
526		}
527		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
528		rem := &recordingRemote{}
529		handshakes := 0
530		clk := &fakeClock{now: time.Unix(1000, 0)}
531		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
532		if h.activeSpec != 1 || h.activeAddr != dup || h.idx != 0 {
533			t.Fatalf("boot active = (%d,%v) idx=%d, want (1,%v) idx=0", h.activeSpec, h.activeAddr, h.idx, dup)
534		}
535	
536		// The standby hostname (spec 0) re-resolves onto the SAME AddrPort as the active spec-1
537		// literal. A bare-value re-map would rebind the active pointer to spec 0's duplicate at
538		// flat index 0; the spec-scoped identity must keep it on spec 1 (now at flat index 1).
539		h.updateResolution(0, []netip.AddrPort{dup})
540		if rem.calls != 0 || handshakes != 0 {
541			t.Fatalf("cross-spec duplicate re-resolution touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
542		}
543		if h.activeSpec != 1 || h.activeAddr != dup {
544			t.Fatalf("active pointer spuriously re-mapped to (%d,%v), want (1,%v) (own spec's entry)", h.activeSpec, h.activeAddr, dup)
545		}
546		if h.idx != 1 {
547			t.Fatalf("active flattened idx = %d, want 1 (spec-1 dup, past spec-0's duplicate at 0)", h.idx)
548		}
549	
550		// A subsequent hub-loss advance must walk the flattened order to spec 2's tail literal
551		// at flat index 2 — NOT stall on the duplicate at index 0/1.
552		clk.advance(testSettle + time.Second)
553		h.check()
554		if rem.calls != 1 || rem.last != tail {
555			t.Fatalf("advance after duplicate: SetPeerRemote=%d last=%v, want 1 and %v (flattened order to spec-2 tail)", rem.calls, rem.last, tail)
556		}
557		if h.activeSpec != 2 || h.activeAddr != tail || h.idx != 2 {
558			t.Fatalf("post-advance active = (%d,%v) idx=%d, want (2,%v) idx=2", h.activeSpec, h.activeAddr, h.idx, tail)
559		}
560		if handshakes != 1 {
561			t.Fatalf("advance re-handshakes=%d, want 1", handshakes)
562		}
563	}
